import React, { useCallback, useRef, useState } from 'react';
import { Layer, Stage } from 'react-konva';
import './App.css';
import Toolbar from './components/Toolbar';
import PenTool from './tools/PenTool';

const CANVAS_SIZE = 10000; // Large virtual canvas size

function App() {
  const [tool, setTool] = useState('pen');
  const [isDrawing, setIsDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const stageRef = useRef();
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [stageScale, setStageScale] = useState(1);

  // Get pointer position (works for both mouse and touch)
  const getPointerPosition = (e) => {
    const stage = e.target.getStage();
    return stage.getPointerPosition();
  };

  const handlePointerDown = useCallback((e) => {
    if (tool === 'pen') {
      setIsDrawing(true);
      const pos = getPointerPosition(e);
      const adjustedPos = {
        x: (pos.x - stagePos.x) / stageScale,
        y: (pos.y - stagePos.y) / stageScale
      };
      setLines([...lines, { points: [adjustedPos.x, adjustedPos.y], tool: 'pen' }]);
    }
  }, [tool, lines, stagePos, stageScale]);

  const handlePointerMove = useCallback((e) => {
    if (!isDrawing || tool !== 'pen') return;

    const point = getPointerPosition(e);
    const adjustedPoint = {
      x: (point.x - stagePos.x) / stageScale,
      y: (point.y - stagePos.y) / stageScale
    };

    let lastLine = lines[lines.length - 1];
    lastLine.points = lastLine.points.concat([adjustedPoint.x, adjustedPoint.y]);

    lines.splice(lines.length - 1, 1, lastLine);
    setLines(lines.concat());
  }, [isDrawing, tool, lines, stagePos, stageScale]);

  const handlePointerUp = useCallback(() => {
    setIsDrawing(false);
  }, []);

  const handleWheel = useCallback((e) => {
    e.evt.preventDefault();

    const stage = stageRef.current;
    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const newScale = e.evt.deltaY > 0 ? oldScale * 0.9 : oldScale * 1.1;

    const newPos = {
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    };

    setStageScale(newScale);
    setStagePos(newPos);
  }, []);

  // Handle pinch-to-zoom for tablets
  const handleTouchMove = useCallback((e) => {
    e.evt.preventDefault();

    if (e.evt.touches && e.evt.touches.length === 2) {
      // Pinch to zoom logic
      const touch1 = e.evt.touches[0];
      const touch2 = e.evt.touches[1];

      const dist = Math.sqrt(
        Math.pow(touch2.clientX - touch1.clientX, 2) +
        Math.pow(touch2.clientY - touch1.clientY, 2)
      );

      // Store initial distance for comparison
      if (!stageRef.current.lastDist) {
        stageRef.current.lastDist = dist;
        return;
      }

      const scale = stageScale * (dist / stageRef.current.lastDist);
      setStageScale(Math.max(0.1, Math.min(5, scale))); // Limit zoom range
      stageRef.current.lastDist = dist;
    } else {
      stageRef.current.lastDist = 0;
      handlePointerMove(e);
    }
  }, [handlePointerMove, stageScale]);

  return (
    <div className="app">
      <Toolbar 
        activeTool={tool} 
        onToolChange={setTool}
      />
      <div className="canvas-container">
        <Stage
          ref={stageRef}
          width={window.innerWidth}
          height={window.innerHeight}
          onMouseDown={handlePointerDown}
          onMousemove={handlePointerMove}
          onMouseup={handlePointerUp}
          onTouchStart={handlePointerDown}
          onTouchMove={handleTouchMove}
          onTouchEnd={handlePointerUp}
          onWheel={handleWheel}
          scaleX={stageScale}
          scaleY={stageScale}
          x={stagePos.x}
          y={stagePos.y}
          draggable={tool === 'pan' || !isDrawing}
        >
          <Layer>
            {/* Grid background */}
            {/* We'll add grid later if needed */}

            {/* Render all drawing lines */}
            {lines.map((line, i) => (
              <PenTool
                key={i}
                points={line.points}
              />
            ))}
          </Layer>
        </Stage>
      </div>
    </div>
  );
}

export default App;
